mapper.select:
select
    (
        select count(1)
        from jst_order_main
        where create_time  >=  #{todayStart}
          and create_time  <  #{todayEnd}
          and order_status != 'cancelled'
          and del_flag = '0'
    ) as today_order_count,
    (
        select coalesce(sum(net_pay_amount), 0.00)
        from jst_order_main
        where pay_time  >=  #{todayStart}
          and pay_time  <  #{todayEnd}
          and order_status in ('paid', 'reviewing', 'in_service', 'aftersale', 'completed', 'closed')
          and del_flag = '0'
    ) as today_revenue,
    (
        (
            select coalesce(sum(net_pay_amount), 0.00)
            from jst_order_main
            where pay_time  >=  #{monthStart}
              and pay_time  <  #{monthEnd}
              and order_status in ('paid', 'reviewing', 'in_service', 'aftersale', 'completed', 'closed')
              and del_flag = '0'
        ) -
        (
            select coalesce(sum(actual_cash), 0.00)
            from jst_refund_record
            where complete_time  >=  #{monthStart}
              and complete_time  <  #{monthEnd}
              and status = 'completed'
              and del_flag = '0'
        )
    ) as month_revenue,
    (
        select count(1)
        from jst_user
        where del_flag = '0'
    ) as total_user_count,
    (
        select count(1)
        from jst_contest
        where del_flag = '0'
    ) as total_contest_count,
    (
        select count(1)
        from jst_enroll_record
        where del_flag = '0'
    ) as total_enroll_count
